import asyncio
from concurrent.futures import ProcessPoolExecutor
from worker import embed_chunk, init_worker

# Long-lived singleton — created once at application startup
_pool: ProcessPoolExecutor | None = None


def get_pool() -> ProcessPoolExecutor:
    global _pool
    if _pool is None:
        _pool = ProcessPoolExecutor(
            max_workers=4,
            initializer=init_worker,
            initargs=("BAAI/bge-small-en-v1.5",),
        )
    return _pool


async def get_embeddings(chunks: list[str]) -> list[list[float]]:
    loop = asyncio.get_running_loop()

    def _batch() -> list[list[float]]:
        return list(get_pool().map(embed_chunk, chunks, chunksize=32))

    # run_in_executor submits _batch to a thread; _batch calls the process pool
    return await loop.run_in_executor(None, _batch)

