async def embed_handler(texts: list[str]):
    loop = asyncio.get_running_loop()
    return await loop.run_in_executor(None, lambda: list(_pool.map(embed, texts)))

from concurrent.futures import ProcessPoolExecutor, as_completed

def risky(n: int) -> float:
    if n % 100 == 0:
        raise ValueError(f"bad input: {n}")
    return 1.0 / n

with ProcessPoolExecutor(max_workers=2) as pool:
    futures = [pool.submit(risky, i) for i in range(500)]
    results = []
    for fut in as_completed(futures):
        try:
            results.append(fut.result())
        except Exception as exc:
            print(f"Task failed: {exc}")  # handle per-task, not globally

