import atexit, signal
from concurrent.futures import BrokenProcessPool, ProcessPoolExecutor

_pool: ProcessPoolExecutor | None = None


def _make_pool() -> ProcessPoolExecutor:
    return ProcessPoolExecutor(max_workers=4, initializer=_init)


def safe_submit(fn, *args):
    """Submit a task; transparently restart the pool if it is broken."""
    global _pool
    if _pool is None:
        _pool = _make_pool()
    try:
        return _pool.submit(fn, *args)
    except BrokenProcessPool:
        _pool = _make_pool()
        return _pool.submit(fn, *args)


def _shutdown(*_):
    if _pool:
        _pool.shutdown(wait=False, cancel_futures=True)


atexit.register(_shutdown)
signal.signal(signal.SIGTERM, _shutdown)
